// Onboarding
function setupOnboarding() {
    const overlay = document.getElementById('onboarding-overlay');
    const panel = document.getElementById('onboarding-panel');

    if (localStorage.getItem('tre-onboarding-done')) {
        overlay.style.display = 'none';
        return;
    }

    // Step 1: Velkomst
    showOnboardingStep1();

    function showOnboardingStep1() {
        panel.innerHTML = `
            <img src="tre_logo.png" alt="TRE logo" style="width: 75%; max-width: 275px; margin: 0 auto 25px; display: block; border: 2px solid #000; border-radius: 8px;">
            <h1>Willkommen bei TRE</h1>
            <p>Erkunde, wie TRE wirkt, durch ein interaktives Modell mit sechs Perspektiven — angepasst an dein Bedürfnis.</p>
            <button id="onboarding-next" style="
                font-family: 'Times New Roman', Times, serif;
                padding: 14px 40px;
                background: #6c82a9;
                color: white;
                border: none;
                border-radius: 8px;
                font-size: 1.1rem;
                cursor: pointer;
                transition: background 0.2s;
            ">Loslegen</button>
        `;
        document.getElementById('onboarding-next').addEventListener('click', showOnboardingStep2);
    }

    function showOnboardingStep2() {
        panel.innerHTML = `
            <h1>Wähle dein Perspektiv</h1>
            <p>Wie möchtest du TRE erkunden?</p>
            <div class="onboarding-modes">
                <button class="onboarding-mode-btn" data-mode="klient">
                    <div class="ob-title">Für Klienten</div>
                    <div class="ob-desc">TRE einfach und zugänglich verstehen</div>
                </button>
                <button class="onboarding-mode-btn" data-mode="fusion">
                    <div class="ob-title">Body Fusion Work</div>
                    <div class="ob-desc">Michaels körperlich anspruchsvolle Gruppenpraxis</div>
                </button>
                <button class="onboarding-mode-btn" data-mode="videnskab">
                    <div class="ob-title">Wissenschaftlich</div>
                    <div class="ob-desc">Neurobiologie und Forschungsgrundlage hinter TRE</div>
                </button>
                <button class="onboarding-mode-btn" data-mode="sclerose">
                    <div class="ob-title">Für Menschen mit MS</div>
                    <div class="ob-desc">TRE angepasst an chronische neurologische Erkrankung</div>
                </button>
                <button class="onboarding-mode-btn" data-mode="oevelser">
                    <div class="ob-title">Übungen</div>
                    <div class="ob-desc">Konkrete Übungen und praktische Anleitung</div>
                </button>
            </div>
        `;

        panel.querySelectorAll('.onboarding-mode-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                const mode = btn.dataset.mode;
                finishOnboarding(mode);
            });
        });
    }

    function finishOnboarding(mode) {
        localStorage.setItem('tre-onboarding-done', 'true');

        // Sæt valgt mode
        currentMode = mode;
        document.querySelectorAll('.mode-btn').forEach(b => {
            b.classList.toggle('active', b.dataset.mode === mode);
        });

        // Fade out overlay
        overlay.style.transition = 'opacity 0.4s ease';
        overlay.style.opacity = '0';
        setTimeout(() => {
            overlay.style.display = 'none';
            showWelcome();

            // Pulse-hint på en cirkel
            const firstCircle = document.querySelector('.outer-circle');
            if (firstCircle) {
                firstCircle.classList.add('circle-hint');
                setTimeout(() => {
                    firstCircle.classList.remove('circle-hint');
                }, 6000);
            }
        }, 400);
    }
}

// Initialize
document.addEventListener('DOMContentLoaded', () => {
    setupModeButtons();
    setupCircleClicks();
    setupConnectionClicks();
    setupMenu();
    setupSearch();
    setupOnboarding();

    // Vis welcome kun hvis onboarding allerede er gennemført
    if (localStorage.getItem('tre-onboarding-done')) {
        showWelcome();
    }
});

// Mode selector - VISUELT TYDELIGT
function setupModeButtons() {
    const buttons = document.querySelectorAll('.mode-btn');
    buttons.forEach(btn => {
        btn.addEventListener('click', () => {
            // Visual feedback
            buttons.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');

            const oldMode = currentMode;
            currentMode = btn.dataset.mode;

            // Flash effekt for at vise noget skete
            const infoPanel = document.getElementById('info-content');
            infoPanel.style.opacity = '0.3';
            setTimeout(() => {
                infoPanel.style.opacity = '1';
            }, 150);

            // Nulstil altid til velkomst ved mode-skift, scroll til tekst
            showWelcome(true);

        });
    });
}

// Scroll helper - scroller så info-panel fylder hele skærmen
function scrollToElement(id) {
    const el = document.getElementById(id);
    if (el) {
        setTimeout(() => {
            const rect = el.getBoundingClientRect();
            // Scroll til elementets top minus en lille smule så diagrammet er helt væk
            const offset = window.scrollY + rect.top - 5;
            window.scrollTo({ top: offset, behavior: 'smooth' });
        }, 50);
    }
}

